cd /app && python3 -c "
import pandas as pd, numpy as np
np.random.seed(0)
d=pd.read_csv('bn_sample_10k.csv')

# DAG edges child<-parent
parents={'U':[], 'Y':['U'], 'R':['U'], 'D':['U','Y'], 'M':['U','R']}

# learned_dag.csv (to,from)
rows=[]
for c,ps in parents.items():
    for p in ps: rows.append((c,p))
pd.DataFrame(rows,columns=['to','from']).to_csv('learned_dag.csv',index=False)

# fit linear gaussian per node
def fit(node,ps):
    y=d[node].values
    if ps:
        X=np.column_stack([np.ones(len(d))]+[d[p].values for p in ps])
    else:
        X=np.ones((len(d),1))
    b,*_=np.linalg.lstsq(X,y,rcond=None)
    r=y-X@b
    return b, r.std(ddof=len(b))
coef={n:fit(n,ps) for n,ps in parents.items()}
for n in coef: print(n, coef[n][0].round(3), 'sd',round(coef[n][1],3))
"
